class Solution:
    def consecutiveNumbersSum(self, n):
        m = n
        while m % 2 == 0:
            m //= 2
        count = 0
        d = 1
        while d * d <= m:
            if m % d == 0:
                count += 1
                if d != m // d:
                    count += 1
            d += 1
        return count

