var consecutiveNumbersSum = function(n) {
    let m = n;
    while (m % 2 === 0) m = Math.floor(m / 2);
    let count = 0;
    for (let d = 1; d * d <= m; d++) {
        if (m % d === 0) {
            count += 1;
            if (d !== m / d) count += 1;
        }
    }
    return count;
};
